    function getAlerts(since) {
        var cutoff = since ? new Date(since).getTime() : 0;
        return alerts.filter(function (a) { return a.timestamp >= cutoff; });
    }

    // ── Helpers ─────────────────────────────────────────────────

    function formatBooking(b) {
